// ============================================================
// Enrich a thin grant description.
// Input (webhook body): { id?, title, funder_name, source_url, description }
// Returns: { description, enriched: boolean, source: 'original'|'source_url'|'deep_crawl'|'web_search' }
//
// When `id` is supplied, the enriched description is ALSO written
// back to central_grants.id=<id> via PATCH. Callers that want async
// fire-and-forget semantics (via the enrich-queue workflow) can rely
// on that PATCH instead of awaiting the return payload. Legacy
// callers that inspect the return value still work unchanged.
//
// Flow:
//   1. Scrape source_url, strip HTML, LLM-extract description.
//   2. If still < 200 chars, crawl same-domain links on that page whose
//      anchor text matches the grant title or common detail/apply keywords.
//      Fetch top 5 in parallel, concat, LLM-extract again.
//   3. If still < 200 chars, DuckDuckGo search for the grant, fetch top 10
//      results in parallel, concat, LLM-extract again.
//   4. Any failure anywhere -> return original description unchanged.
// Model: gpt-4.1-mini. No external search APIs.
// ============================================================

const raw = $input.first().json;
const input = raw.body || raw;
const id = (input.id || input.grant_id || '').toString().trim() || null;
const title = (input.title || '').toString();
const funder = (input.funder_name || '').toString();
const sourceUrl = (input.source_url || '').toString();
const origDescription = (input.description || '').toString();

const THIN_LIMIT = 200;
const openAiKey = 'REPLACE_ME';
const UA = 'Mozilla/5.0 (compatible; GrantScanner/1.0; +https://grant.thebrownmine.com)';

const SUPABASE_URL = 'https://fgudhlcktsstwpxwtwzz.supabase.co/rest/v1';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6ImZndWRobGNrdHNzdHdweHd0d3p6Iiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MDk2NjA5NSwiZXhwIjoyMDg2NTQyMDk1fQ.lDXOCM7CStNfF0G-ZENg5x1dyQ0ytXHGtJ8DjQNd03I';

function stripHtml(html) {
  return (html || '')
    .replace(/<script[\s\S]*?<\/script>/gi, ' ')
    .replace(/<style[\s\S]*?<\/style>/gi, ' ')
    .replace(/<noscript[\s\S]*?<\/noscript>/gi, ' ')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/\s+/g, ' ')
    .trim();
}

async function llmExtract(pageText) {
  if (!pageText || pageText.length < 50) return '';
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.openai.com/v1/chat/completions',
      headers: {
        'Authorization': 'Bearer ' + openAiKey,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        model: 'gpt-4.1-mini',
        messages: [
          { role: 'system', content: 'You extract grant descriptions from web page text. Return ONLY valid JSON in the form {"description": string}. The description must cover (when present) the grant purpose, who is eligible, award amounts, and deadlines. Be faithful to the source text - do not invent facts. If the page text is unusable, irrelevant, or an error page, return {"description": ""}.' },
          { role: 'user', content: 'Grant title: ' + title + '\nFunder: ' + funder + '\n\nPage text:\n' + pageText.slice(0, 8000) }
        ],
        temperature: 0,
        response_format: { type: 'json_object' },
      }),
      json: true,
      timeout: 30000,
    });
    const txt = (resp && resp.choices && resp.choices[0] && resp.choices[0].message && resp.choices[0].message.content) || '{}';
    const cleaned = txt.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(cleaned);
    return ((parsed && parsed.description) || '').toString().trim();
  } catch (e) {
    return '';
  }
}

async function fetchText(url, timeoutMs) {
  try {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: url,
      headers: { 'User-Agent': UA, 'Accept': 'text/html,application/xhtml+xml' },
      timeout: timeoutMs || 15000,
    });
    return typeof resp === 'string' ? resp : JSON.stringify(resp);
  } catch (e) {
    return '';
  }
}

async function patchCentralGrant(rowId, description) {
  if (!rowId || !description) return { ok: false, skipped: true };
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: SUPABASE_URL + '/central_grants?id=eq.' + encodeURIComponent(rowId),
      headers: {
        'apikey':        SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Content-Type':  'application/json',
        'Prefer':        'return=minimal',
      },
      body: JSON.stringify({ description: description }),
    });
    return { ok: true };
  } catch (e) {
    return { ok: false, message: String(e.message || e).slice(0, 400) };
  }
}

let enriched = origDescription;
let enrichedSource = 'original';
let pageHtml = '';

// ---- STEP 1: Scrape source_url ----
if (sourceUrl) {
  pageHtml = await fetchText.call(this, sourceUrl, 20000);
  if (pageHtml) {
    const text = stripHtml(pageHtml);
    const extracted = await llmExtract.call(this, text);
    if (extracted && extracted.length >= THIN_LIMIT) {
      enriched = extracted;
      enrichedSource = 'source_url';
    }
  }
}

// ---- STEP 2: Deep-crawl links on the source page ----
if ((enriched || '').length < THIN_LIMIT && pageHtml && sourceUrl) {
  try {
    let origin = '';
    try { origin = new URL(sourceUrl).origin; } catch (e) {}

    const anchors = [];
    const aRe = /<a\s+[^>]*href="([^"]+)"[^>]*>([\s\S]*?)<\/a>/gi;
    let am;
    while ((am = aRe.exec(pageHtml)) !== null) {
      const href = am[1];
      const text = stripHtml(am[2]);
      if (!href || !text || text.length < 3) continue;
      anchors.push({ href, text });
    }

    const resolved = [];
    for (const a of anchors) {
      let abs;
      try { abs = new URL(a.href, sourceUrl).toString(); } catch (e) { continue; }
      if (!abs.startsWith('http')) continue;
      if (abs === sourceUrl) continue;
      if (/\.(pdf|jpg|jpeg|png|gif|zip|doc|docx|xls|xlsx|mp4|mp3)(\?|#|$)/i.test(abs)) continue;
      if (/(facebook|twitter|x\.com|linkedin|instagram|youtube|pinterest)\.com/i.test(abs)) continue;
      resolved.push({ href: abs, text: a.text });
    }

    const titleLc = title.toLowerCase();
    const titleWords = titleLc.split(/\s+/).filter(w => w.length > 3);
    const keywords = ['detail', 'program', 'guideline', 'apply', 'rfp', 'full description', 'overview', 'more information', 'eligibility', 'criteria', 'learn more', 'read more', 'opportunity', 'funding'];
    const noiseExact = /^(home|login|sign in|sign up|register|privacy|terms|contact|about us|menu|search|cart|donate|subscribe|careers|news|blog|events|staff|board)$/i;

    const scored = [];
    for (const a of resolved) {
      if (noiseExact.test(a.text.trim())) continue;
      const t = a.text.toLowerCase();
      let score = 0;

      if (titleLc && titleLc.length >= 8 && t.includes(titleLc)) {
        score += 10;
      } else if (titleWords.length > 0) {
        const matched = titleWords.filter(w => t.includes(w)).length;
        if (matched >= Math.max(2, Math.min(3, titleWords.length))) score += 5 + matched;
        else if (matched > 0) score += matched;
      }

      for (const kw of keywords) {
        if (t.includes(kw)) { score += 1; break; }
      }
      if (origin && a.href.startsWith(origin)) score += 2;

      if (score > 0) scored.push({ href: a.href, text: a.text, score });
    }

    scored.sort((x, y) => y.score - x.score);
    const seen = new Set();
    const picks = [];
    for (const a of scored) {
      if (seen.has(a.href)) continue;
      seen.add(a.href);
      picks.push(a);
      if (picks.length >= 5) break;
    }

    if (picks.length > 0) {
      const pages = await Promise.all(picks.map(async (a) => {
        const h = await fetchText.call(this, a.href, 12000);
        return h ? stripHtml(h).slice(0, 3000) : '';
      }));
      const concat = pages.filter(Boolean).join('\n\n---\n\n').slice(0, 8000);
      if (concat) {
        const extracted = await llmExtract.call(this, concat);
        if (extracted && extracted.length >= THIN_LIMIT && extracted.length > (enriched || '').length) {
          enriched = extracted;
          enrichedSource = 'deep_crawl';
        }
      }
    }
  } catch (e) {}
}

// ---- STEP 3: Web search fallback via DuckDuckGo HTML ----
if ((enriched || '').length < THIN_LIMIT && title) {
  try {
    const q = encodeURIComponent('"' + title + '" ' + funder);
    const ddg = await fetchText.call(this, 'https://html.duckduckgo.com/html/?q=' + q, 20000);
    const urls = [];
    if (ddg) {
      const dRe = /<a[^>]+class="result__a"[^>]+href="([^"]+)"/g;
      let dm;
      while ((dm = dRe.exec(ddg)) !== null && urls.length < 10) {
        let u = dm[1];
        const uddg = u.match(/[?&]uddg=([^&]+)/);
        if (uddg) {
          try { u = decodeURIComponent(uddg[1]); } catch (e) {}
        }
        if (u && u.startsWith('http') && u !== sourceUrl) urls.push(u);
      }
    }

    if (urls.length > 0) {
      const pages = await Promise.all(urls.map(async (u) => {
        const h = await fetchText.call(this, u, 12000);
        return h ? stripHtml(h).slice(0, 2000) : '';
      }));
      const concat = pages.filter(Boolean).join('\n\n---\n\n').slice(0, 8000);
      if (concat) {
        const extracted2 = await llmExtract.call(this, concat);
        if (extracted2 && extracted2.length >= THIN_LIMIT && extracted2.length > (enriched || '').length) {
          enriched = extracted2;
          enrichedSource = 'web_search';
        }
      }
    }
  } catch (e) {}
}

// ---- Self-write back to central_grants when id supplied ----
let persisted = false;
if (id && enrichedSource !== 'original' && (enriched || '').length > origDescription.length) {
  const r = await patchCentralGrant.call(this, id, enriched);
  persisted = !!r.ok;
}

return [{
  json: {
    description: enriched || origDescription,
    enriched: enrichedSource !== 'original',
    source: enrichedSource,
    persisted: persisted,
    id: id,
  }
}];
